  async nationIdSearchBtn() {
    this.searchFormStatus.valid = true;
    try {
      this.showLoader = true;
      if (this.searchForm.valid) {
        let nationId: string = this.searchForm.value.nationId;
        let clientById: ClientInfo = await this.clientService.getClientById(
          nationId
        );

        // client Exist
        if (clientById) {
          let canOfficerEdit: boolean = await this.authService
            .getAccessRights()
            .then(async (accessRights) => {
              return accessRights.map((x) => x.window_code).includes("5564");
            });
          if (!canOfficerEdit) {
            return this.alertService.showAlertError(
              "غير مسموح لك التعديل",
              false
            );
          }
          if (
            clientById.client_type_code == "4" ||
            clientById.client_type_code == "2"
            // clientById.client_type_code == "3"
          ) {
            return await this.alertService.showAlertError(
              "هذا العميل مسجل في مجموعة / شركات",
              false
            );
          }

          this.existingClientInfo = clientById;
          this.searchFormStatus.visible = false;
          this.showEditClientComponent = true;
        }
        // new client
        else {
          let clientByIdWithAnyBranch =
            await this.clientService.getClientByIdWithAnyBranch(nationId);
          if (clientByIdWithAnyBranch) {
            let alertMessage: string =
              `الرقم القومي مكرر` +
              "<br>" +
              `مع العميل ${clientByIdWithAnyBranch.client_name}` +
              "<br>" +
              `بالفرع ${clientByIdWithAnyBranch.branch_name}` +
              "<br>" +
              `ويحمل كود رقم ${clientByIdWithAnyBranch.client_code}` +
              "<br>" +
              `مع مندوب:  ${clientByIdWithAnyBranch.officer_name}`;
            await this.alertService.showAlertError(alertMessage, false);
            return;
          }

          let clientByIdFromClientRegistration =
            await this.clientService.getClientByIdFromClientRegistration(
              nationId
            );
          if (clientByIdFromClientRegistration.count) {
            return await this.alertService.showAlertError(
              "هذا العميل قيد المراجعة",
              false
            );
          }

          this.extractDataFromNationId();
          this.searchFormStatus = { valid: false, visible: false };
          this.wizardForm.goToNextStep();
          this.personalFormStatus.visible = true;
        }
      }
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  noDateGreaterToday(control: FormControl) {
    const selectedDate = new Date(control.value);
    const currentDate = new Date();
    if (selectedDate > currentDate) {
      return { DateIsGreater: true };
    }
  }
  changeIssuanceDate(date: string) {
    const issuanceDate = new Date(date);
    const issuanceYear = issuanceDate.getFullYear();
    const issuanceMonth = issuanceDate.getMonth();
    const issuanceDay = issuanceDate.getDate();
    const NationalIDExpirationPeriod = Number(
      this.NationalIDExpirationPeriod.value
    );

    const expiryDate = new Date(
      issuanceYear + NationalIDExpirationPeriod,
      issuanceMonth,
      issuanceDay
    );
    this.personalForm.patchValue({
      nationIdExpiryDate: this.datePipe.transform(expiryDate, "yyyy-MM-dd"),
    });
  }
  async submitPersonalForm() {
    try {
      this.showLoader = true;
      this.personalFormStatus.valid = true;

      if (!this.personalForm.valid) {
        return;
      }
      if (this.smsActive === true && this.mobileReadOnly === false) {
        return this.alertService.showAlertError(
          "برجاء ارسال رمز التحقق",
          false
        );
      }
      const mobileNumber: string =
        this.personalForm?.value?.mobileNumber.toString();
      if (
        this.checkIfMobileNumberExistFlag.value === "1" &&
        (await this.clientService.checkRepeatedMobile(mobileNumber)) === 1 &&
        this.smsActive === false
      ) {
        return this.alertService.showAlertError("رقم المحمول(1) مكرر", false);
      }
      this.personalFormStatus.visible = false;
      this.homeFormStatus.visible = true;
      this.wizardForm.goToNextStep();
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  extractDataFromNationId() {
    let nationId: string = this.searchForm.value.nationId;
    let gender: string;
    let century: string;
    let decade: string;
    let month: string;
    let day: string;
    gender = Number(nationId.slice(12, -1)) % 2 !== 0 ? "1" : "2";
    switch (Number(nationId.slice(0, -13))) {
      case 1: {
        century = "18";
        break;
      }
      case 2: {
        century = "19";
        break;
      }
      case 3: {
        century = "20";
        break;
      }
      case 4: {
        century = "21";
        break;
      }
    }
    decade = nationId.slice(1, -11);
    month = nationId.slice(3, -9);
    day = nationId.slice(5, -7);
    this.personalForm.patchValue({
      nationId: nationId,
      gender: gender,
      birthDate: century + decade + "-" + month + "-" + day,
    });
  }
  clientNameCleaner = (clientName: string): string => {
    const prefixPatterns = [
      { pattern: /عبد/gi, replacement: "عبد" },
      { pattern: /ابو/gi, replacement: "ابو" },
    ];

    for (const { pattern, replacement } of prefixPatterns) {
      clientName = clientName.replace(pattern, replacement);
    }
    clientName = clientName.replace(/\s+/g, " ");
    return clientName.trim();
  };
  async sendingOtp() {
    this.personalFormStatus.valid = true;
    if (!this.personalForm.valid) {
      return;
    }
    let mobileNumber: string = this.personalForm.value.mobileNumber;
    if ((await this.clientService.checkRepeatedMobile(mobileNumber)) === 1) {
      return this.alertService.showAlertError("رقم المحمول(1) مكرر", false);
    }
    this.smsModal.isOpen = true;
    this.startingSmsCountDown();
    await this.smsService.OTP(mobileNumber);
  }
  startingSmsCountDown = (): Promise<boolean> => {
    this.smsCountDown = 30;
    this.canResendSmsResult = false;
    return new Promise((resolve) => {
      this.intervalId = setInterval(() => {
        this.smsCountDown -= 1; // every second (-1) from the CountDown
        if (this.smsCountDown <= 0) {
          clearInterval(this.intervalId);
          resolve(true);
          this.canResendSmsResult = true;
          this.smsCountDown = null;
        }
      }, 1000);
    });
  };
  closingSmsModal() {
    clearInterval(this.intervalId);
    this.smsModal.isOpen = false;
  }
  async smsCheckOtp() {
    if (!this.smsForm.valid) {
      return;
    }
    let mobileNumber: string = this.personalForm.value.mobileNumber;
    if (
      !(await this.smsService.VerifyOTP(
        mobileNumber,
        this.smsForm.value.otp.toString()
      ))
    ) {
      return this.alertService.showAlertError("رمز التحقق غير سليم", false);
    }
    this.mobileReadOnly = true;
    this.smsModal.dismiss();
  }
